text:
(In reply to Dan Langille from comment #4)

Hi Dan,

thank you for looking into it. Your blog post about poudriere in a jail was key resource for my setup, with main difference in vnet - your setup is vnet whereas mine isn't. Could this have an impact on fakeroot?

I ran testport but it fails in stage phase with:

===>   sympa-6.2.72_2 depends on package: p5-DBD-mysql>=0 - found
===>   sympa-6.2.72_2 depends on package: perl5>=5.36<5.37 - found
===>   Generating temporary packing list
===> Creating groups
===> Creating users
fakeroot daemon: socket (Protocol not supported)
fakeroot: error while starting the `faked' daemon.
usage: kill [-s signal_name] pid ...
       kill -l [exit_status]
       kill -signal_name pid ...
       kill -signal_number pid ...
*** Error code 1

Here's my jail.conf:

path            = "/home/jail/${host.hostname}";
exec.start      = "/bin/sh /etc/rc";
exec.stop       = "/bin/sh /etc/rc.shutdown";
exec.clean;
mount.devfs;

pkg2_example_com {
  host.hostname    = pkg2.kappastar.org;
  host.domainname  = kappastar.com;
  ip4.addr         = 'lo1|127.0.1.55/32';
  ip4.addr        += 'em0|192.0.2.55/32';
  ip6.addr        += 'lo1|::55/128';
  children.max     = 200;
  enforce_statfs   = 1;
  sysvmsg          = new;
  sysvsem          = new;
  sysvshm          = new;
  persist;
  allow.chflags;
  allow.mlock;
  allow.mount;
  allow.mount.devfs;
  allow.mount.fdescfs;
  allow.mount.nullfs;
  allow.mount.procfs;
  allow.mount.tmpfs;
  allow.mount.zfs;
  allow.raw_sockets;
  allow.socket_af;

  exec.created    += "zfs jail $name home/poudriere";
  exec.created    += "zfs set jailed=on home/poudriere";
}
